    "command": "// FLAIL — Roll Mighty Potions\n// Draws from the Mighty Potions rolltable using its own formula.\n\nlet table = game.tables?.getName?.(\"Mighty Potions\") ?? null;\nif (!table) {\n  const pack = game.packs.get(\"world.flail-rolltables\");\n  if (pack) {\n    const idx = await pack.getIndex();\n    const entry = idx.find(e => e.name === \"Mighty Potions\");\n    if (entry) table = await pack.getDocument(entry._id);\n  }\n}\nif (!table) {\n  ui.notifications?.error(\"Mighty Potions table not found \\u2014 is the FLAIL Rolltables compendium loaded?\");\n  return;\n}\n\nui.notifications?.info(\"Rolling Mighty Potion (d10)...\");\nawait table.draw();\n",
