    "_id": "ac3881148bbf1f38",
    "name": "Build City Theme",
    "img": "icons/svg/village.svg",
    "type": "script",
    "scope": "global",
    "command": "// FLAIL — Build City Theme\n// Rolls all six theme columns plus the What Is Happening? event, and posts\n// them as a single chat card so the GM can improvise a city.\n\nconst rtPack = game.packs.get(\"world.flail-rolltables\");\nif (!rtPack) { ui.notifications?.error(\"FLAIL Rolltables compendium not loaded.\"); return; }\n\nconst THEME_TABLES = [\n  { label: \"Origin\",     name: \"City Origin Story\" },\n  { label: \"Defence\",    name: \"City Main Defence\" },\n  { label: \"Feature\",    name: \"City Notable Feature\" },\n  { label: \"Government\", name: \"City Government\" },\n  { label: \"Industry\",   name: \"City Industry & Trade\" },\n  { label: \"Oddity\",     name: \"City Oddity\" },\n  { label: \"Happening\",  name: \"City Event\" }\n];\n\nconst idx = await rtPack.getIndex();\nconst rows = [];\nfor (const { label, name } of THEME_TABLES) {\n  const entry = idx.find(e => e.name === name);\n  if (!entry) { rows.push(`<li><strong>${label}:</strong> <em>(table missing)</em></li>`); continue; }\n  const table = await rtPack.getDocument(entry._id);\n  const draw = await table.roll();\n  const text = draw.results?.[0]?.text ?? \"?\";\n  rows.push(`<li><strong>${label}:</strong> ${text}</li>`);\n}\n\nChatMessage.create({\n  speaker: ChatMessage.getSpeaker(),\n  content: `\n<div style=\"background:#f6f0e1;border:2px solid #b58b3e;border-radius:4px;padding:0.7em 1em;\">\n  <div style=\"font-family:'Modesto Condensed','Cinzel',serif;font-size:1.2em;color:#6a4d0e;border-bottom:1px solid #b58b3e;padding-bottom:0.3em;margin-bottom:0.5em;\">\n    City Theme\n  </div>\n  <ul style=\"margin:0;padding-left:1.3em;font-size:0.9em;\">${rows.join(\"\")}</ul>\n</div>`\n});\n",
