    "_id": "5055ce7b289f44d9",
    "name": "Roll Civic Building",
    "img": "icons/svg/house.svg",
    "type": "script",
    "scope": "global",
    "command": "// FLAIL — Roll Civic Building\n// Rolls one building from the Civic (suit) table with d4 sub-roll\n// and any nested tavern/black-market chaining.\n\nconst rtPack = game.packs.get(\"world.flail-rolltables\");\nif (!rtPack) { ui.notifications?.error(\"FLAIL Rolltables compendium not loaded.\"); return; }\nconst uniquePack = game.packs.get(\"world.flail-unique-items\");\n\n\nasync function rollBuilding(suitTableName, rtPack, uniquePack) {\n  const idx = await rtPack.getIndex();\n  const entry = idx.find(e => e.name === suitTableName);\n  if (!entry) return { label: \"?\", type: suitTableName, description: \"table missing\" };\n  const table = await rtPack.getDocument(entry._id);\n  const draw = await table.roll();\n  const rawText = draw.results?.[0]?.text ?? \"\";\n\n  // Parse \"<strong>LABEL.</strong> Building type: (1) x, (2) y, (3) z, (4) w.\"\n  const labelMatch = rawText.match(/<strong>([^<]+)\\.<\\/strong>\\s*(.+)/);\n  const cardLabel = labelMatch ? labelMatch[1] : \"?\";\n  const rest = labelMatch ? labelMatch[2] : rawText;\n\n  // Split \"Building type: (rest of description)\"\n  const colon = rest.indexOf(\":\");\n  const buildingType = colon > -1 ? rest.slice(0, colon) : rest;\n  const remainder = colon > -1 ? rest.slice(colon + 1).trim() : \"\";\n\n  // Detect variant list \"(1) a, (2) b, (3) c, (4) d.\"\n  const variantMatch = remainder.match(/^\\(1\\)\\s*([^,]+),\\s*\\(2\\)\\s*([^,]+),\\s*\\(3\\)\\s*([^,]+),\\s*\\(4\\)\\s*([^\\.]+)/);\n  let variant = \"\";\n  if (variantMatch) {\n    const roll = await new Roll(\"1d4\").evaluate();\n    const chosen = variantMatch[roll.total];\n    variant = chosen?.trim() ?? \"\";\n  }\n\n  // Nested rolls\n  let nested = \"\";\n  if (/roll random tavern/i.test(remainder)) {\n    const tavernNames = [\"Tavern Name 1\", \"Tavern Name 2\", \"Tavern Meal\", \"Tavern Drink\"];\n    const parts = [];\n    for (const tname of tavernNames) {\n      const e = idx.find(x => x.name === tname);\n      if (e) {\n        const t = await rtPack.getDocument(e._id);\n        const d = await t.roll();\n        parts.push(d.results?.[0]?.text ?? \"?\");\n      }\n    }\n    nested = ` &mdash; <em>${parts[0]} ${parts[1]}: ${parts[2]}, ${parts[3]}</em>`;\n  }\n  if (/four random Unique Items/i.test(remainder) && uniquePack) {\n    const uidx = await uniquePack.getIndex();\n    const shuffled = [...uidx].sort(() => Math.random() - 0.5).slice(0, 4);\n    const items = shuffled.map(u => `@UUID[Compendium.world.flail-unique-items.Item.${u._id}]{${u.name}}`);\n    nested = `<br><em style=\"font-size:0.85em;\">Auctioning: ${items.join(\", \")}</em>`;\n  }\n\n  const flavour = variant\n    ? `<strong>${buildingType}</strong> &mdash; ${variant}${nested}`\n    : `<strong>${buildingType}</strong>: ${remainder}${nested}`;\n  return { label: cardLabel, type: buildingType, description: flavour };\n}\n\n\nconst b = await rollBuilding(\"Civic Buildings\", rtPack, uniquePack);\nChatMessage.create({\n  speaker: ChatMessage.getSpeaker(),\n  content: `\n<div style=\"background:#f6f0e1;border:2px solid #b58b3e;border-radius:4px;padding:0.6em 1em;\">\n  <div style=\"font-family:'Modesto Condensed','Cinzel',serif;font-size:1.15em;color:#6a4d0e;border-bottom:1px solid #b58b3e;padding-bottom:0.3em;margin-bottom:0.5em;\">\n    ♥ Civic &mdash; ${b.label}\n  </div>\n  <p style=\"margin:0;font-size:0.9em;\">${b.description}</p>\n</div>`\n});\n",
    "flags": {},
    "ownership": {
      "default": 2
    },
